// === WHITELIST + ROUTER (v3) ===
// v3: текст persistent reply-keyboard кнопок маппим в соответствующие slash-команды
//     ДО анализа msg.text — чтобы тап по кнопке вёл по тому же маршруту, что
//     ручной ввод /vpsk, /clear и т.д. Меню (текст кнопок) — в Send Command Reply.

const BUTTON_TO_CMD = {
  '\uD83D\uDCE5 Загрузить выписку':         '/vpsk',
  '\uD83D\uDD04 Сверить с банком':          '/reconcile',
  '\uD83D\uDCCA Сводный реестр':            '/update',
  '\u2753 Незакрытые позиции':              '/missing',
  '\uD83D\uDCC4 Последние записи':          '/status',
  '\uD83D\uDD17 Ссылка на отчёт':           '/report',
  '\uD83D\uDDD1\uFE0F Очистить лист Банк':  '/clear',
  '\u2139 Помощь':                          '/help'
};

const allowed = ($env.TELEGRAM_ADMIN_CHAT_ID || '').split(',').map(id => id.trim());
const msg = $input.first().json.message || {};
const chatId = String(msg.chat?.id || '');

if (!chatId || !allowed.includes(chatId)) {
  return [];
}

// Если пришёл текст кнопки persistent-keyboard — превращаем его в slash-команду.
let textForRouting = msg.text;
if (textForRouting) {
  const mapped = BUTTON_TO_CMD[textForRouting.trim()];
  if (mapped) textForRouting = mapped;
}

let outputIndex = 3;
let payload = { chatId };

if (msg.photo && msg.photo.length > 0) {
  outputIndex = 0;
  payload.type = 'photo';
  payload.file_id = msg.photo[msg.photo.length - 1].file_id;
  payload.mime_type = 'image/jpeg'; // Telegram сжимает фото в JPEG, но WF-02/03 всё равно нормализует MIME по magic-bytes
} else if (msg.document) {
  const mime = msg.document.mime_type || 'application/octet-stream';
  // Пропускаем любой документ — WF-02/03 сам выполнит MIME-нормализацию (NFR-11)
  outputIndex = 0;
  payload.type = 'document';
  payload.file_id = msg.document.file_id;
  payload.mime_type = mime;
  payload.file_size = msg.document.file_size || 0;
} else if (msg.voice) {
  outputIndex = 0;
  payload.type = 'voice';
  payload.file_id = msg.voice.file_id;
} else if (textForRouting && textForRouting.startsWith('/')) {
  outputIndex = 1;
  payload.text = textForRouting;
} else if (textForRouting) {
  outputIndex = 0;
  payload.type = 'text';
  payload.text = textForRouting;
}

payload.outputIndex = outputIndex;
return [{ json: payload }];

