// Получаем ответ от HTTP Request к WF-02/03
const raw = $input.first().json;
const data = raw.confirmationText ? raw : (raw.data || raw.body || raw);

if (!data.confirmationText) {
  const prevChatId = $('Whitelist + Router').first().json.chatId;
  return [{ json: {
    chatId: prevChatId,
    confirmationText: '⚠️ Ошибка обработки. Попробуйте ещё раз.'
  }}];
}

return [{ json: {
  chatId: String(data.chatId || $('Whitelist + Router').first().json.chatId),
  confirmationText: data.confirmationText
}}];

// === COMMAND HANDLER v2.4 ===
// /vpsk       → routeTo: 'wf06-stmt'  (запрашиваем выписку)
// /reconcile  → routeTo: 'wf07'       (сверка BY + PL)
// /missing    → routeTo: 'wf07-misc'  (незакрытые позиции)
// /report     → routeTo: 'wf07-misc'  (последний отчёт)
// /update     → routeTo: 'wf08'       (объединение Реестр + Банк)
// /clear      → routeTo: 'wf01-clear' (очистка листа «Банк»)  ← v2.4
// остальные   → routeTo: 'local'      (текстовый ответ прямо здесь)

const chatId = $input.first().json.chatId;
const text   = $input.first().json.text || '';
const parts  = text.trim().split(/\s+/);
const cmd    = parts[0].toLowerCase().replace(/@\w+/, '');
const args   = parts.slice(1);

// /vpsk
if (cmd === '/vpsk') {
  return [{ json: {
    chatId,
    routeTo: 'wf06-stmt',
    reply: '\uD83D\uDCCE Пришлите выписку банка.\n\n'         + 'Форматы: PDF, DOCX, CSV, TXT.\n\n'         + 'Поддерживаются:\n'         + '\uD83C\uDDE7\uD83C\uDDFE Приорбанк BY\n'         + '\uD83C\uDDF5\uD83C\uDDF1 PKO Bank Polski PL\n\n'         + 'Можно загружать выписку несколько раз — новые транзакции будут добавлены к существующим (дубли отсеиваются). Полная очистка — /clear.\n\n'         + 'Сессия действует 10 минут.'
  }}];
}

// /reconcile → WF-07
if (cmd === '/reconcile') {
  let period = '';
  const p = args[0] || '';
  if (/^\d{4}-\d{2}$/.test(p)) period = p;
  return [{ json: { chatId, routeTo: 'wf07', period, mode: 'reconcile', reply: '' } }];
}

// /missing → WF-07
if (cmd === '/missing') {
  return [{ json: { chatId, routeTo: 'wf07-misc', mode: 'missing', reply: '' } }];
}

// /report → WF-07
if (cmd === '/report') {
  return [{ json: { chatId, routeTo: 'wf07-misc', mode: 'report', reply: '' } }];
}

// /update → WF-08 (объединение Реестр + Банк в общий документ)
if (cmd === '/update') {
  return [{ json: { chatId, routeTo: 'wf08', reply: '' } }];
}

// /clear → локальная очистка листа «Банк»  ← v2.4
if (cmd === '/clear') {
  return [{ json: { chatId, routeTo: 'wf01-clear', reply: '' } }];
}

// Локальные ответы
const replies = {
  '/start':  '\uD83D\uDC4B Привет!\n\nОтправьте PDF, фото документа, голосовое или текст о платеже — я запишу в реестр.\n\nКнопки внизу — основные команды. /help — список команд.',
  '/help':   '\uD83D\uDCD6 Команды:\n/start — приветствие и меню\n/status — последние записи\n/vpsk — загрузить банковскую выписку\n/reconcile [YYYY-MM] — сверка реестра с банком\n/missing — незакрытые позиции\n/report — ссылка на полный отчёт\n/update — пересобрать сводный реестр\n/clear — очистить лист «Банк»\n/settings — настройки\n/cancel — отмена',
  '/cancel': '\u2705 Отменено.',
  '/status': '\uD83D\uDCCB Последние записи — в листе Реестр.'
};

let reply = replies[cmd];

if (!reply && cmd === '/settings') {
  const sub = args.join(' ');
  if (!sub)                           reply = '\u2699\uFE0F Настройки:\n/settings recipients list\n/settings recipients add @user\n/settings recipients remove @user\n/settings schedule show';
  else if (sub === 'recipients list') reply = '\uD83D\uDCCB Получатели: откройте лист «Получатели» в Google Sheets.';
  else if (sub.startsWith('recipients add'))    reply = '\u2705 Добавьте строку в лист «Получатели»: chat_id | username | owner/accountant | TRUE';
  else if (sub.startsWith('recipients remove')) reply = '\u2705 Поставьте active=FALSE в листе «Получатели».';
  else if (sub === 'schedule show')   reply = '\uD83D\uDD50 Сверка: 1-е число, 09:00 UTC+3 (Europe/Minsk)';
  else                                reply = `\u2753 Неизвестная подкоманда: ${sub}`;
}

if (!reply) reply = `\u2753 Неизвестная команда: ${cmd}`;

return [{ json: { chatId, routeTo: 'local', reply } }];

