let chatId = '';
try { chatId = $('Whitelist + Router').first().json.chatId || ''; } catch(e) { return []; }
if (!chatId) return [];
return [{ json: { chatId, text: '⚠️ Ошибка. Попробуйте ещё раз.' } }];

// === EVALUATE SESSION ===
// Проверяет, активна ли сессия /vpsk для данного chatId.
// Сессия активна только для файлов (photo/document), не для voice/text.
// Входные данные: результат Check VPSK Session (строка из листа Сессии или пустой объект).
// Оригинальные данные роутинга берём из Whitelist + Router.

const sessionData = $input.first().json;
const origData    = $('Whitelist + Router').first().json;

// Сессия актуальна только для файлов
const isFile = (origData.type === 'photo' || origData.type === 'document');

let sessionActive = false;
if (isFile && sessionData && sessionData.chat_id && sessionData.command === 'vpsk') {
  try {
    const expires = new Date(sessionData.expires_at);
    if (expires > new Date()) sessionActive = true;
  } catch (e) {}
}

return [{
  json: {
    ...origData,
    _sessionRoute: sessionActive ? 1 : 0,
    _sessionChatId: sessionData.chat_id || ''
  }
}];

