// Источник chatId — Command Handler. Google Sheets clear не пробрасывает json,
// поэтому достаём chatId из предыдущего узла напрямую.
const chatId = $('Command Handler').first().json.chatId;
return [{ json: {
  chatId,
  reply: '\uD83D\uDDD1\uFE0F Лист «Банк» очищен. Все банковские операции удалены.\n\nЗагрузить выписку снова — /vpsk.'
}}];
